To write unit tests for the `topological_sort` function using `pytest`, we need to cover various scenarios including the happy path, edge cases, and error cases. Here's how you can structure the tests:

```python
import pytest

def topological_sort(graph: dict) -> list:
    visited = set()
    result = []
    def dfs(node):
        if node in visited:
            return
        visited.add(node)
        for neighbor in graph.get(node, []):
            dfs(neighbor)
        result.append(node)
    for node in graph:
        dfs(node)
    return result[::-1]

def test_topological_sort_happy_path():
    graph = {
        'a': ['b', 'c'],
        'b': ['d'],
        'c': ['d'],
        'd': []
    }
    expected = ['a', 'c', 'b', 'd']  # One of the valid topological orders
    assert topological_sort(graph) == expected

def test_topological_sort_single_node():
    graph = {'a': []}
    expected = ['a']
    assert topological_sort(graph) == expected

def test_topological_sort_disconnected_graph():
    graph = {
        'a': [],
        'b': [],
        'c': ['d'],
        'd': []
    }
    expected = ['c', 'd', 'a', 'b']  # One of the valid topological orders
    assert topological_sort(graph) == expected

def test_topological_sort_empty_graph():
    graph = {}
    expected = []
    assert topological_sort(graph) == expected

def test_topological_sort_cyclic_graph():
    graph = {
        'a': ['b'],
        'b': ['c'],
        'c': ['a']
    }
    # Topological sort is not possible for cyclic graphs, but this function does not handle cycles.
    # It will return a result, but it won't be a valid topological sort.
    result = topological_sort(graph)
    assert 'a' in result and 'b' in result and 'c' in result
    assert result.index('a') > result.index('b') and result.index('b') > result.index('c')

def test_topological_sort_with_self_loop():
    graph = {
        'a': ['a']
    }
    # Similar to cyclic graph, this will not be a valid topological sort.
    result = topological_sort(graph)
    assert 'a' in result

def test_topological_sort_with_multiple_edges():
    graph = {
        'a': ['b', 'c'],
        'b': ['c'],
        'c': []
    }
    expected = ['a', 'b', 'c']  # One of the valid topological orders
    assert topological_sort(graph) == expected

def test_topological_sort_with_no_edges():
    graph = {
        'a': [],
        'b': [],
        'c': []
    }
    expected = ['a', 'b', 'c']  # One of the valid topological orders
    assert topological_sort(graph) == expected

def test_topological_sort_with_repeated_nodes():
    graph = {
        'a': ['b'],
        'b': ['c'],
        'c': ['a'],
        'a': []  # Duplicate node 'a'
    }
    # The function should handle duplicate keys by using the last occurrence.
    expected = ['b', 'c', 'a']  # One of the valid topological orders
    assert topological_sort(graph) == expected

# Run the tests
if __name__ == "__main__":
    pytest.main()
```

### Explanation:

- **Happy Path**: Tests a simple DAG with a clear topological order.
- **Single Node**: Tests a graph with a single node.
- **Disconnected Graph**: Tests a graph with multiple disconnected components.
- **Empty Graph**: Tests an empty graph.
- **Cyclic Graph**: Tests a graph with a cycle. The function does not handle cycles, so it will return a result, but it won't be a valid topological sort.
- **Self Loop**: Tests a graph with a self-loop.
- **Multiple Edges**: Tests a graph with multiple edges between nodes.
- **No Edges**: Tests a graph where nodes have no edges.
- **Repeated Nodes**: Tests a graph with repeated nodes in the dictionary, which should be handled by using the last occurrence of the node.

These tests cover a wide range of scenarios to ensure the function behaves as expected.
